import sqlite3
import sys

def create_connection(db_file):
    """Create a database connection to the SQLite database specified by db_file."""
    conn = None
    try:
        conn = sqlite3.connect(db_file)
    except sqlite3.Error as e:
        print(f"Error connecting to database: {e}")
        sys.exit(1)
    return conn

def create_table(conn):
    """Create a table if it does not exist yet."""
    try:
        sql_create_table = """CREATE TABLE IF NOT EXISTS contacts (
                                id integer PRIMARY KEY,
                                name text NOT NULL,
                                phone text NOT NULL,
                                email text NOT NULL
                            );"""
        conn.execute(sql_create_table)
    except sqlite3.Error as e:
        print(f"Error creating table: {e}")
        sys.exit(1)

def add_contact(conn, name, phone, email):
    """Add a new contact to the contacts table."""
    try:
        sql_insert_contact = """INSERT INTO contacts(name, phone, email)
                                VALUES(?, ?, ?);"""
        conn.execute(sql_insert_contact, (name, phone, email))
        conn.commit()
    except sqlite3.Error as e:
        print(f"Error adding new contact: {e}")

def update_contact(conn, name, phone, email):
    """Update a contact in the contacts table based on the name."""
    try:
        sql_update_contact = """UPDATE contacts
                                SET phone = ?, email = ?
                                WHERE name = ?;"""
        conn.execute(sql_update_contact, (phone, email, name))
        conn.commit()
    except sqlite3.Error as e:
        print(f"Error updating contact: {e}")

def delete_contact(conn, name):
    """Delete a contact from the contacts table based on the name."""
    try:
        sql_delete_contact = "DELETE FROM contacts WHERE name = ?;"
        conn.execute(sql_delete_contact, (name,))
        conn.commit()
    except sqlite3.Error as e:
        print(f"Error deleting contact: {e}")

def search_contact(conn, name):
    """Search for a contact by name."""
    try:
        sql_search_contact = "SELECT * FROM contacts WHERE name LIKE ?;"
        cursor = conn.execute(sql_search_contact, (f'%{name}%',))
        return cursor.fetchall()
    except sqlite3.Error as e:
        print(f"Error searching for contact: {e}")

def list_contacts(conn):
    """List all contacts in alphabetical order by name."""
    try:
        sql_list_contacts = "SELECT * FROM contacts ORDER BY name;"
        cursor = conn.execute(sql_list_contacts)
        return cursor.fetchall()
    except sqlite3.Error as e:
        print(f"Error listing contacts: {e}")

def main():
    database = "contacts.db"
    conn = create_connection(database)
    create_table(conn)

    while True:
        print("\nOptions:")
        print("1. Add contact")
        print("2. Update contact")
        print("3. Delete contact")
        print("4. Search contact")
        print("5. List all contacts")
        print("6. Exit")
        choice = input("Enter choice: ")

        if choice == '1':
            name = input("Enter contact name: ")
            phone = input("Enter phone number: ")
            email = input("Enter email: ")
            add_contact(conn, name, phone, email)
            print("Contact added.")
        elif choice == '2':
            name = input("Enter contact name: ")
            phone = input("Enter new phone number: ")
            email = input("Enter new email: ")
            update_contact(conn, name, phone, email)
            print("Contact updated.")
        elif choice == '3':
            name = input("Enter contact name to delete: ")
            delete_contact(conn, name)
            print("Contact deleted.")
        elif choice == '4':
            name = input("Enter contact name to search: ")
            results = search_contact(conn, name)
            for row in results:
                print(row)
        elif choice == '5':
            results = list_contacts(conn)
            for row in results:
                print(row)
        elif choice == '6':
            break
        else:
            print("Invalid choice. Please choose a number between 1 and 6.")

    conn.close()

if __name__ == '__main__':
    main()
