from flask import Flask, request, jsonify
import requests
from redis import Redis
import json
from functools import wraps
from oauth2client import verify_token
from datetime import datetime, timedelta

app = Flask(__name__)
redis_instance = Redis(host='localhost', port=6379, db=0)

# Configuration for OpenWeatherMap
API_KEY = 'your_openweathermap_api_key'
WEATHER_URL = 'https://api.openweathermap.org/data/2.5/weather'

# Simple OAuth 2.0 token verification decorator
def require_oauth(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization')
        if not auth_header or not auth_header.startswith('Bearer '):
            return jsonify({'error': 'Authorization header is expected with Bearer token'}), 403

        token = auth_header.split(' ')[1]
        if not verify_token(token):
            return jsonify({'error': 'Invalid or expired token'}), 403

        return f(*args, **kwargs)
    return decorated_function

@app.route('/forecast', methods=['GET'])
@require_oauth
def get_forecast():
    city = request.args.get('city')
    date = request.args.get('date')

    if not city or not date:
        return jsonify({'error': 'Both city and date parameters are required'}), 400

    try:
        query_date = datetime.strptime(date, '%Y-%m-%d')
        if query_date < datetime.now():
            return jsonify({'error': 'Date must be today or later'}), 400
    except ValueError:
        return jsonify({'error': 'Invalid date format, use YYYY-MM-DD'}), 400

    cache_key = f'forecast:{city}'
    cached = redis_instance.get(cache_key)
    if cached:
        return json.loads(cached), 200

    params = {
        'q': city,
        'appid': API_KEY
    }
    response = requests.get(WEATHER_URL, params=params)
    if response.status_code != 200:
        return jsonify({'error': 'Failed to fetch weather data'}), 500

    data = response.json()
    redis_instance.setex(cache_key, timedelta(hours=2), json.dumps(data))
    return data, 200

if __name__ == '__main__':
    app.run(debug=True)
