from flask import Flask, request, jsonify, abort
from flask_sqlalchemy import SQLAlchemy
from sqlalchemy.exc import IntegrityError
from marshmallow import Schema, fields, validate, ValidationError
from functools import wraps
import jwt
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'postgresql://username:password@localhost/dbname'
app.config['SECRET_KEY'] = 'your_secret_key'
db = SQLAlchemy(app)
limiter = Limiter(app, key_func=lambda: get_jwt_identity(), default_limits=["5 per minute"])

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    display_name = db.Column(db.String(30))
    email = db.Column(db.String(120), unique=True)
    bio = db.Column(db.String(160))

    def update(self, data):
        for key, value in data.items():
            setattr(self, key, value)
        db.session.commit()

class UserSchema(Schema):
    display_name = fields.Str(validate=validate.Length(min=3, max=30))
    email = fields.Email()
    bio = fields.Str(validate=validate.Length(max=160))

user_schema = UserSchema()

def token_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get('Authorization')
        if not token:
            abort(401, description="Missing token")
        try:
            data = jwt.decode(token, app.config['SECRET_KEY'], algorithms=["HS256"])
        except:
            abort(401, description="Invalid token")
        return f(*args, **kwargs)
    return decorated

def get_jwt_identity():
    token = request.headers.get('Authorization')
    data = jwt.decode(token, app.config['SECRET_KEY'], algorithms=["HS256"])
    return data['username']

@app.route('/api/v1/users/me', methods=['PATCH'])
@token_required
@limiter.limit("5 per minute")
def update_user():
    token = request.headers.get('Authorization')
    data = jwt.decode(token, app.config['SECRET_KEY'], algorithms=["HS256"])
    user = User.query.filter_by(username=data['username']).first()

    json_data = request.json
    try:
        valid_data = user_schema.load(json_data, partial=True)
    except ValidationError as err:
        return jsonify(err.messages), 400

    if 'email' in valid_data:
        if User.query.filter(User.email == valid_data['email']).first():
            abort(409, description="Email already in use")

    try:
        user.update(valid_data)
    except IntegrityError:
        db.session.rollback()
        abort(409, description="Email already in use")

    return jsonify({"message": "User updated successfully"}), 200

if __name__ == '__main__':
    db.create_all()
    app.run(debug=True)
