from django.shortcuts import render, redirect
from django.contrib.auth.decorators import login_required
import speech_recognition as sr

from .models import Pronunciation

@login_required
def index(request):
    return render(request, 'myapp/index.html')

@login_required
def assess_pronunciation(request):
    if request.method == 'POST':
        word = request.POST['word']
        audio_file = request.FILES['audio_file']

        recognizer = sr.Recognizer()
        with sr.AudioFile(audio_file) as source:
            audio_data = recognizer.record(source)

        try:
            recognized_text = recognizer.recognize_google(audio_data)
            score = score_pronunciation(word, recognized_text)
            Pronunciation.objects.create(user=request.user, word=word, score=score)
            return render(request, 'myapp/result.html', {'score': score})
        except sr.UnknownValueError:
            return render(request, 'myapp/result.html', {'error': 'Could not understand audio'})

    return redirect('index')

def score_pronunciation(expected, actual):
    # rudimentary scoring
    return int(expected.lower() == actual.lower()) * 100

