/**
 * Normalizes and removes accents from a string.
 * @param {string} text - The text to be normalized.
 * @return {string} - The normalized text.
 */
function normalizeText(text) {
  return unorm.nfd(text).replace(/[\u0300-\u036f]/g, '');
}

/**
 * Searches for products based on a query.
 * @param {string} query - The search query.
 * @return {Promise<Array>} - A promise that resolves to an array of products.
 */
async function searchProducts(query) {
  const normalizedQuery = normalizeText(query);
  // Assume db.find is a method to find products based on a query.
  return db.find({ name: normalizedQuery });
}

module.exports = {
  searchProducts,
};
