import Vue from 'vue';
import Vuex from 'vuex';
import axios from 'axios';

Vue.use(Vuex);

export default new Vuex.Store({
  state: {
    friendRequests: [],
    potentialFriends: []
  },
  mutations: {
    SET_FRIEND_REQUESTS(state, requests) {
      state.friendRequests = requests;
    },
    SET_POTENTIAL_FRIENDS(state, users) {
      state.potentialFriends = users;
    },
    ADD_FRIEND_REQUEST(state, id) {
      const index = state.potentialFriends.findIndex(user => user.id === id);
      if (index !== -1) {
        state.friendRequests.push(state.potentialFriends[index]);
        state.potentialFriends.splice(index, 1);
      }
    },
    REMOVE_FRIEND_REQUEST(state, id) {
      const index = state.friendRequests.findIndex(user => user.id === id);
      if (index !== -1) {
        state.potentialFriends.push(state.friendRequests[index]);
        state.friendRequests.splice(index, 1);
      }
    }
  },
  actions: {
    fetchFriendRequests({ commit }) {
      axios.get('/api/friends/requests')
        .then(response => {
          commit('SET_FRIEND_REQUESTS', response.data);
        })
        .catch(error => console.error('Error fetching friend requests:', error));
    },
    fetchPotentialFriends({ commit }) {
      axios.get('/api/users/potential_friends')
        .then(response => {
          commit('SET_POTENTIAL_FRIENDS', response.data);
        })
        .catch(error => console.error('Error fetching potential friends:', error));
    },
    sendFriendRequest({ commit }, id) {
      commit('ADD_FRIEND_REQUEST', id);
    },
    acceptFriendRequest({ commit }, id) {
      commit('REMOVE_FRIEND_REQUEST', id);
    },
    cancelFriendRequest({ commit }, id) {
      commit('REMOVE_FRIEND_REQUEST', id);
    }
  }
});
