class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end_of_word = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word):
        node = self.root
        for char in word.lower():
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

    def search(self, prefix):
        node = self.root
        for char in prefix.lower():
            if char not in node.children:
                return []
            node = node.children[char]
        return self._find_words_from_node(node, prefix)

    def _find_words_from_node(self, node, prefix):
        words = []
        if node.is_end_of_word:
            words.append(prefix)
        for char, next_node in node.children.items():
            words.extend(self._find_words_from_node(next_node, prefix + char))
        return words

    def serialize(self):
        result = []
        def dfs(node, path):
            if node.is_end_of_word:
                result.append(''.join(path))
            for char, child in node.children.items():
                dfs(child, path + [char])

        dfs(self.root, [])
        return '|'.join(result)

    def deserialize(self, data):
        if not data:
            return
        words = data.split('|')
        for word in words:
            self.insert(word)

# Usage:
trie = Trie()
trie.insert("print")
trie.insert("printf")
trie.insert("PrintLine")

# Auto-completion suggestions
print(trie.search("pri"))  # Output: ['print', 'printf']
print(trie.search("Print"))  # Output: ['printline', 'print', 'printf']

# Serialization and Deserialization
serialized_data = trie.serialize()
new_trie = Trie()
new_trie.deserialize(serialized_data)
print(new_trie.search("pri"))  # Output: ['print', 'printf']
