const Koa = require('koa');
const Router = require('koa-router');
const bodyParser = require('koa-bodyparser');
const hmacSHA256 = require('crypto-js/hmac-sha256');
const rateLimit = require('koa-ratelimit');
const logger = require('koa-logger');
const axios = require('axios');

const app = new Koa();
const router = new Router();

// Database or in-memory store for webhooks
const webhooks = {};

// Helper to validate HMAC signature
const validateHMAC = (secret, payload, signature) => {
  const generated = hmacSHA256(JSON.stringify(payload), secret).toString();
  return generated === signature;
};

// Middleware for rate limiting
app.use(rateLimit({
  driver: 'memory',
  db: new Map(),
  duration: 60000,
  errorMessage: 'Rate limit exceeded.',
  id: (ctx) => ctx.ip,
  headers: true,
  max: 100
}));

// Middleware for logging
app.use(logger());

// Middleware for parsing request bodies
app.use(bodyParser());

// CRUD operations for webhooks
router
  .post('/webhooks', async (ctx) => {
    const { url, secret, events } = ctx.request.body;
    if (!url || !secret || !events) {
      ctx.throw(400, 'Missing url, secret or events');
    }

    const id = Date.now().toString();
    webhooks[id] = { url, secret, events };
    ctx.body = { id };
  })
  .get('/webhooks', async (ctx) => {
    ctx.body = webhooks;
  })
  .put('/webhooks/:id', async (ctx) => {
    const { id } = ctx.params;
    const { url, secret, events } = ctx.request.body;
    if (!webhooks[id]) {
      ctx.throw(404, 'Webhook not found');
    }
    webhooks[id] = { url, secret, events };
    ctx.body = webhooks[id];
  })
  .delete('/webhooks/:id', async (ctx) => {
    const { id } = ctx.params;
    if (!webhooks[id]) {
      ctx.throw(404, 'Webhook not found');
    }
    delete webhooks[id];
    ctx.status = 204;
  });

// Event trigger and dispatching POST request
const triggerEvent = async (event, data) => {
  Object.entries(webhooks).forEach(([id, { url, secret, events }]) => {
    if (events.includes(event)) {
      const hmacSignature = hmacSHA256(JSON.stringify(data), secret).toString();
      axios.post(url, data, {
        headers: {
          'X-Signature': `sha256=${hmacSignature}`
        }
      }).catch(error => console.error(`Failed to trigger webhook ${id}: ${error}`));
    }
  });
};

// Example: trigger webhook on new product added
triggerEvent('productAdded', { productId: 123, name: 'New Product' });

app.use(router.routes()).use(router.allowedMethods());
app.listen(3000);

