import stripe
from typing import Dict


class StripePaymentProcessor:
    def __init__(self, api_key: str):
        """
        Initialize the StripePaymentProcessor with the provided API key.

        :param api_key: API key to access the Stripe API
        """
        stripe.api_key = api_key

    def process_payment(self, amount: int, currency: str, source: str) -> Dict[str, str]:
        """
        Process a payment using Stripe.

        :param amount: Amount to be charged (in smallest currency unit, e.g., cents)
        :param currency: Currency code (e.g., 'usd')
        :param source: Stripe source object (e.g., a token representing a credit card)
        :return: Dict with payment status or error details
        """
        try:
            charge = stripe.Charge.create(
                amount=amount,
                currency=currency,
                source=source,
                description="E-commerce platform payment"
            )
            return {'status': 'success', 'charge_id': charge.id}
        except stripe.error.CardError as e:
            # Since it's a decline, stripe.error.CardError will be caught
            return {'status': 'error', 'message': str(e.user_message)}
        except stripe.error.RateLimitError:
            # Too many requests made to the API too quickly
            return {'status': 'error', 'message': 'Rate limit error'}
        except stripe.error.InvalidRequestError:
            # Invalid parameters were supplied to Stripe's API
            return {'status': 'error', 'message': 'Invalid parameters'}
        except stripe.error.AuthenticationError:
            # Authentication with Stripe's API failed
            return {'status': 'error', 'message': 'Authentication failed'}
        except stripe.error.APIConnectionError:
            # Network communication with Stripe failed
            return {'status': 'error', 'message': 'Network error'}
        except stripe.error.StripeError:
            # Display a very generic error to the user
            return {'status': 'error', 'message': 'Internal error'}
        except Exception as e:
            # Something else happened, completely unrelated to Stripe
            return {'status': 'error', 'message': 'An unexpected error occurred'}

