import numpy as np

class Experiment:
    def __init__(self, name, **parameters):
        self.name = name
        self.parameters = parameters
        self.results = {}

    def set_parameters(self, **parameters):
        self.parameters.update(parameters)

    def run(self):
        # Example calculation using numpy
        if all(param in self.parameters for param in ['initial_velocity', 'angle', 'mass']):
            g = 9.81  # acceleration due to gravity (m/s^2)
            v0 = self.parameters['initial_velocity']
            angle_deg = self.parameters['angle']
            angle_rad = np.radians(angle_deg)
            t_flight = (2 * v0 * np.sin(angle_rad)) / g
            range = (v0 ** 2) * np.sin(2 * angle_rad) / g

            self.results['time_of_flight'] = t_flight
            self.results['distance_traveled'] = range
        else:
            raise ValueError("Required parameters for the experiment are not fully provided.")

    def get_results(self):
        return self.results

    def compare_with(self, other_experiment):
        # Simple comparison based on the distance traveled
        if 'distance_traveled' in self.results and 'distance_traveled' in other_experiment.get_results():
            return self.results['distance_traveled'] - other_experiment.get_results()['distance_traveled']
        else:
            raise ValueError("Comparison requires both experiments to be run with complete results.")
