import { Controller, Post, Body, HttpException, HttpStatus, UseGuards } from '@nestjs/common';
import { PaymentService } from './payment.service';
import { CreatePaymentDto } from './payment.dto';
import { ApiKeyGuard } from '../auth/api-key.guard';
import { ApiOperation, ApiResponse, ApiTags } from '@nestjs/swagger';

@ApiTags('payments')
@Controller('payments')
export class PaymentController {
  constructor(private readonly paymentService: PaymentService) {}

  @Post()
  @UseGuards(ApiKeyGuard)
  @ApiOperation({ summary: 'Create a payment' })
  @ApiResponse({ status: 201, description: 'Payment created', type: CreatePaymentDto })
  @ApiResponse({ status: 400, description: 'Invalid input' })
  @ApiResponse({ status: 401, description: 'Unauthorized' })
  @ApiResponse({ status: 502, description: 'Payment gateway error' })
  async create(@Body() createPaymentDto: CreatePaymentDto) {
    try {
      const { paymentId, clientSecret } = await this.paymentService.createPayment(createPaymentDto);
      return { paymentId, clientSecret };
    } catch (error) {
      if (error.status === HttpStatus.BAD_GATEWAY) {
        throw new HttpException({
          error: 'Payment gateway error',
          details: error.message
        }, HttpStatus.BAD_GATEWAY);
      }
      throw error;
    }
  }
}

// payment.service.ts
import { Injectable, HttpException, HttpStatus } from '@nestjs/common';
import { InjectModel } from '@nestjs/mongoose';
import { Model, Session } from 'mongoose';
import { Payment } from './schemas/payment.schema';
import { CreatePaymentDto } from './payment.dto';
import Stripe from 'stripe';

@Injectable()
export class PaymentService {
  private stripeClient = new Stripe(process.env.STRIPE_SECRET, {
    apiVersion: '2020-08-27',
  });

  constructor(@InjectModel(Payment.name) private paymentModel: Model<Payment>) {}

  async createPayment(createPaymentDto: CreatePaymentDto): Promise<{ paymentId: string, clientSecret: string }> {
    const session: Session = await this.paymentModel.db.startSession();
    session.startTransaction();

    try {
      const payment = new this.paymentModel({
        amount: createPaymentDto.amount,
        currency: createPaymentDto.currency,
        customerId: createPaymentDto.customerId,
        description: createPaymentDto.description
      });

      const savedPayment = await payment.save({ session });

      const stripePaymentIntent = await this.stripeClient.paymentIntents.create({
        amount: createPaymentDto.amount,
        currency: createPaymentDto.currency,
        metadata: { paymentId: savedPayment.id }
      });

      savedPayment.stripePaymentIntentId = stripePaymentIntent.id;
      await savedPayment.save({ session });

      await session.commitTransaction();
      session.endSession();

      return {
        paymentId: savedPayment.id,
        clientSecret: stripePaymentIntent.client_secret,
      };
    } catch (error) {
      await session.abortTransaction();
      session.endSession();

      console.error(JSON.stringify({
        error: "Stripe Payment Intent creation failed",
        details: error.message,
      }));

      throw new HttpException('Payment gateway error', HttpStatus.BAD_GATEWAY);
    }
  }
}

