app = Flask(__name__)

client = MongoClient("mongodb://localhost:27017/")
db = client["health_management"]
patients_collection = db["patients"]

valid_conditions = {"Diabetes", "Hypertension", "Asthma", "COVID-19"}

@app.route("/patient/<patient_id>", methods=["PUT"])
def update_patient(patient_id):
    # Authenticate and authorize here
    if not request.is_json:
        return make_response(jsonify({"error": "Request must be JSON"}), 400)

    data = request.get_json()

    # Validate data
    name = data.get("name")
    age = data.get("age")
    conditions = data.get("conditions")

    if not all([name, age, conditions]):
        return make_response(jsonify({"error": "Missing required field"}), 400)

    if not isinstance(age, int) or age < 0:
        return make_response(jsonify({"error": "Age must be a non-negative integer"}), 400)

    if not all(condition in valid_conditions for condition in conditions):
        return make_response(jsonify({"error": "Invalid health condition"}), 400)

    # Update patient record in the database
    try:
        update_result = patients_collection.update_one(
            {"_id": ObjectId(patient_id)},
            {"$set": {"name": name, "age": age, "conditions": conditions}}
        )
        if update_result.matched_count == 0:
            return make_response(jsonify({"error": "No patient found with provided ID"}), 404)
    except Exception as e:
        return make_response(jsonify({"error": str(e)}), 500)

    updated_patient = patients_collection.find_one({"_id": ObjectId(patient_id)})
    updated_patient["_id"] = str(updated_patient["_id"])  # Convert ObjectId to string for JSON serialization

    return jsonify(updated_patient), 200

if __name__ == "__main__":
