import json
import os

class Game:
    def __init__(self):
        self.rooms = {
            "Entrance Hall": {
                "description": "You are in a grand entrance hall. A large chandelier hangs above you.",
                "items": ["notebook", "pen"],
                "exits": {"north": "Library", "east": "Dining Room"}
            },
            "Library": {
                "description": "You are surrounded by towering bookshelves filled with ancient books.",
                "items": ["dusty book", "candle"],
                "exits": {"south": "Entrance Hall"}
            },
            "Dining Room": {
                "description": "A long table that can seat fifty guests dominates the room.",
                "items": ["silverware", "plate"],
                "exits": {"west": "Entrance Hall", "north": "Kitchen"}
            },
            "Kitchen": {
                "description": "You see a variety of cooking utensils and a warm oven that smells like bread.",
                "items": ["knife", "bread"],
                "exits": {"south": "Dining Room"}
            }
        }
        self.current_room = "Entrance Hall"
        self.inventory = []
        self.save_file = "game_save.json"

    def describe_room(self):
        room = self.rooms[self.current_room]
        print(f"\n{room['description']}\n")
        print("Visible items:")
        for item in room["items"]:
            print(f"- {item}")

    def save_game(self):
        # Save the current state of the game (including player inventory and current room) to JSON file
        save_data = {
            "current_room": self.current_room,
            "inventory": self.inventory
        }
        with open(self.save_file, 'w') as file:
            json.dump(save_data, file)
        print("Game saved.")

    def load_game(self):
        # Load the saved game state if the save file exists
        if os.path.exists(self.save_file):
            with open(self.save_file, 'r') as file:
                save_data = json.load(file)
                self.current_room = save_data["current_room"]
                self.inventory = save_data["inventory"]
            print("Game loaded. Continuing from previous save.")
        else:
            print("No saved game found. Starting a new game.")

    def move(self, direction):
        # Handle player movement from room to room
        current_exits = self.rooms[self.current_room]["exits"]
        if direction in current_exits:
            self.current_room = current_exits[direction]
            print(f"You move to the {self.current_room}")
        else:
            print("You can't go that way.")

    def take_item(self, item_name):
        # Allow player to take item from the room and add it to their inventory
        room_items = self.rooms[self.current_room]["items"]
        if item_name in room_items:
            self.inventory.append(item_name)
            room_items.remove(item_name)
            print(f"You take the {item_name}.")
            self.save_game()
        else:
            print("Item not found here.")

    def start_game(self):
        self.load_game()
        while True:
            self.describe_room()
            action = input("What would you like to do? ").strip().lower()
            if action == "quit":
                self.save_game()
                break
            elif action in ["north", "south", "east", "west"]:
                self.move(action)
            elif action.startswith("take "):
                item = action.split(" ", 1)[1]
                self.take_item(item)


if __name__ == "__main__":
    game = Game()
    game.start_game()
