const express = require('express');
const redis = require('redis');

const app = express();
const PORT = 3000;
const REDIS_PORT = 6379;

const client = redis.createClient(REDIS_PORT);

const RATE_LIMIT_WINDOW = 15 * 60 * 1000; // 15 minutes in milliseconds
const RATE_LIMIT_MAX_REQUESTS = 100; // max requests per IP within window

const blockedIps = new Set();

app.use(async (req, res, next) => {
  const ip = req.ip;

  if (blockedIps.has(ip)) {
    console.log(`IP Blocked: ${ip}`);
    return res.status(403).send('Access denied. Your IP address has been blocked due to suspicious activity.');
  }

  const now = Date.now();
  const startTime = now - RATE_LIMIT_WINDOW;

  const key = `req_${ip}`;

  try {
    // Check the number of requests in the current time window
    const requests = await client.zrangebyscore(key, startTime, now);

    if (requests.length >= RATE_LIMIT_MAX_REQUESTS) {
      blockedIps.add(ip);
      console.log(`IP Added to Block List: ${ip}`);
      client.del(key); // Reset the count for the blocked IP
      return res.status(429).send('Too many requests. Please try again later.');
    }

    // Add current timestamp to the sorted set
    client.zadd(key, now, now);
    client.zremrangebyscore(key, 0, startTime); // Clean up outdated entries in the sorted set

    console.log(`Request Allowed: ${ip}`);
    next();
  } catch (error) {
    console.error('Redis error:', error);
    res.status(500).send('Internal server error');
  }  
});

app.get('/admin/blocked', (req, res) => {
  res.status(200).json({
    blockedIPs: Array.from(blockedIps)
  });
});

app.get('/admin/unblock/:ip', (req, res) => {
  const ip = req.params.ip;
  if (blockedIps.has(ip)) {
    blockedIps.delete(ip);
    res.status(200).send(`IP address ${ip} has been unblocked successfully.`);
  } else {
    res.status(404).send('IP address not found in block list.');
  }
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});
