using Microsoft.AspNetCore.Mvc;
using System.ComponentModel.DataAnnotations;
using System.Net.Http;
using Microsoft.Extensions.Caching.Memory;
using System;
using Polly;
using Microsoft.Extensions.Logging;
using Microsoft.AspNetCore.Authorization;
using System.Threading.Tasks;
using Swashbuckle.AspNetCore.Annotations;
using System.Globalization;

namespace CurrencyConversionAPI.Controllers
{
    [ApiController]
    [Route("[controller]")]
    [Authorize]
    public class CurrencyController : ControllerBase
    {
        private readonly IHttpClientFactory _httpClientFactory;
        private readonly IMemoryCache _memoryCache;
        private readonly ILogger<CurrencyController> _logger;

        public CurrencyController(IHttpClientFactory httpClientFactory, IMemoryCache memoryCache, ILogger<CurrencyController> logger)
        {
            _httpClientFactory = httpClientFactory;
            _memoryCache = memoryCache;
            _logger = logger;
        }

        [HttpGet("convert")]
        [SwaggerOperation(Summary = "Converts an amount from one currency to another")]
        [SwaggerResponse(200, "The conversion was successful", typeof(ConversionResponse))]
        [SwaggerResponse(400, "Input validation failed", typeof(ValidationError))]
        [SwaggerResponse(401, "API key is missing or invalid")]
        [SwaggerResponse(503, "External rate service unavailable", typeof(ServiceError))]
        public async Task<IActionResult> Convert(
            [FromQuery, Required, SwaggerParameter("ISO 4217 code of the source currency", Required = true)] string fromCurrency,
            [FromQuery, Required, SwaggerParameter("ISO 4217 code of the target currency", Required = true)] string toCurrency,
            [FromQuery, Required, Range(0.01, double.MaxValue), SwaggerParameter("", Required = true)] decimal amount)
        {
            if (!ModelState.IsValid)
            {
                return BadRequest(new ValidationError(ModelState));
            }

            var cacheKey = $"{fromCurrency}_{toCurrency}";
            if (!_memoryCache.TryGetValue(cacheKey, out decimal exchangeRate))
            {
                var httpClient = _httpClientFactory.CreateClient();
                var retryPolicy = Policy
                                    .HandleResult<HttpResponseMessage>(r => !r.IsSuccessStatusCode)
                                    .WaitAndRetryAsync(new[]
                                    {
                                        TimeSpan.FromSeconds(1),
                                        TimeSpan.FromSeconds(5),
                                        TimeSpan.FromSeconds(10)
                                    });

                var response = await retryPolicy.ExecuteAsync(() => httpClient.GetAsync($"https://api.exchangeratesapi.io/latest?base={fromCurrency}&symbols={toCurrency}"));
                if (!response.IsSuccessStatusCode)
                {
                    _logger.LogError("Failed to fetch rates from external service after retries");
                    return StatusCode(503, new ServiceError("Rate service unavailable", response.ReasonPhrase));
                }

                var rates = await response.Content.ReadAsAsync<RatesResponse>();
                exchangeRate = rates.Rates[toCurrency];
                _memoryCache.Set(cacheKey, exchangeRate, TimeSpan.FromMinutes(5));
            }

            decimal convertedAmount = amount * exchangeRate;
            var result = new ConversionResponse
            {
                FromCurrency = fromCurrency,
                ToCurrency = toCurrency,
                ExchangeRate = exchangeRate,
                OriginalAmount = amount,
                ConvertedAmount = convertedAmount,
                Timestamp = DateTime.UtcNow.ToString(CultureInfo.InvariantCulture)
            };

            return Ok(result);
        }

        public class ConversionResponse
        {
            public string FromCurrency { get; set; }
            public string ToCurrency { get; set; }
            public decimal ExchangeRate { get; set; }
            public decimal OriginalAmount { get; set; }
            public decimal ConvertedAmount { get; set; }
            public string Timestamp { get; set; }
        }

        public class RatesResponse
        {
            public Dictionary<string, decimal> Rates { get; set; }
        }

        public class ValidationError
        {
            public List<string> Errors { get; set; }

            public ValidationError(ModelStateDictionary modelState)
            {
                Errors = new List<string>();
                foreach (var entry in modelState)
                {
                    foreach (var error in entry.Value.Errors)
                    {
                        Errors.Add($"{entry.Key}: {error.ErrorMessage}");
                    }
                }
            }
        }

        public class ServiceError
        {
            public string Error { get; set; }
            public string Details { get; set; }

            public ServiceError(string error, string details)
            {
                Error = error;
                Details = details;
            }
        }
    }
}
