import csv

def read_tasks_from_csv(file_name):
    tasks = []
    with open(file_name, mode='r') as file:
        csv_reader = csv.DictReader(file)
        for row in csv_reader:
            task_name = row['task_name']
            priority = int(row['priority'])
            duration = int(row['duration'])
            tasks.append((task_name, priority, duration))
    return tasks

def sort_tasks(tasks):
    # Sort by priority, then by duration if there are ties
    return sorted(tasks, key=lambda x: (x[1], x[2]))

def print_schedule(sorted_tasks):
    for task in sorted_tasks:
        print(f"Task: {task[0]}, Priority: {task[1]}, Duration: {task[2]}")

def main():
    tasks = read_tasks_from_csv('tasks.csv')
    sorted_tasks = sort_tasks(tasks)
    print_schedule(sorted_tasks)

if __name__ == "__main__":
    main()
